import{_ as o,o as t,c as a,ag as l}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"ide-evolution","description":"","frontmatter":{"title":"ide-evolution","concept":"IDE Evolution","concept_id":"ide-evolution","aliases":["IDE 的演进","Post-IDE-Era"],"sources":["02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] Is the IDE dead_.md"],"related_concepts":["[[claude-code-mastery]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/ide-evolution.md","filePath":"wiki/concepts/ide-evolution.md","lastUpdated":null}'),i={name:"wiki/concepts/ide-evolution.md"};function r(n,e,d,s,u,c){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="ide-evolution-ide-的演进" tabindex="-1">IDE Evolution (IDE 的演进) <a class="header-anchor" href="#ide-evolution-ide-的演进" aria-label="Permalink to &quot;IDE Evolution (IDE 的演进)&quot;">​</a></h1><h2 id="核心辩题-ide-是否已死" tabindex="-1">核心辩题：IDE 是否已死？ <a class="header-anchor" href="#核心辩题-ide-是否已死" aria-label="Permalink to &quot;核心辩题：IDE 是否已死？&quot;">​</a></h2><p>随着 Claude Code、Cursor 和 Antigravity 等 Agentic 工具的兴起，传统的 &quot;Integrated Development Environment&quot; (集成开发环境) 正在发生质变。</p><h2 id="演进趋势" tabindex="-1">演进趋势 <a class="header-anchor" href="#演进趋势" aria-label="Permalink to &quot;演进趋势&quot;">​</a></h2><ol><li><strong>从“编辑工具”到“协同系统”</strong>： <ul><li>传统 IDE 重点在于语法高亮和补全。</li><li>智能体时代 IDE 重点在于<strong>意图理解</strong>与<strong>自主执行</strong>。</li></ul></li><li><strong>终端与 GUI 的融合</strong>： <ul><li>开发者并非完全抛弃 VS Code，但核心逻辑正向具备高权限、高移动性的 CLI (如 Claude Code) 偏移。</li></ul></li><li><strong>ACI (Agent-Computer Interface) 替代 HCI</strong>： <ul><li>未来软件的内部结构将优先为 AI 的理解而设计，而非仅仅为了屏幕显示。</li></ul></li></ol><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>IDE 并没有死，而是进化为了分布式、多智能体协同的<strong>自主开发中心</strong>。</p><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>迁移检查清单</strong>： <ul><li>[ ] 确保代码库中包含 <code>.cursorrules</code> 或 <code>.claudecode.json</code> 定义领域知识。</li><li>[ ] 将常用调试脚本封装为 CLI 工具，而非仅停留在 IDE 按钮上。</li><li>[ ] 习惯“先规划后点击”，在终端先通过 <code>/plan</code> 对齐思路。</li></ul></li><li><strong>混合模式</strong>：不要试图在 CLI 中完成 100% 的 UI 对齐工作。复杂样式调整优先用 Cursor 的 GUI，逻辑重构和全局搜索优先用 Claude Code。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - Is the IDE dead_.html">[AI_IDE_And_CLI] Is the IDE dead_</a></li></ul>',13)])])}const h=o(i,[["render",r]]);export{_ as __pageData,h as default};
